sql:
SELECT user_name
FROM staff_users
WHERE last_login > datetime('now', '-1 hour');

SELECT station_id, station_name
FROM charging_stations
WHERE state_province = 'California';

SELECT station_id, AVG(energy_kWh) AS avg_energy_per_session
FROM charging_sessions
GROUP BY station_id;

SELECT COUNT(*) 
FROM charging_stations 
WHERE status = 'operational';

SELECT station_name
FROM charging_stations
WHERE station_id IN (
    SELECT station_id
    FROM station_maintenance
    WHERE maintenance_cost > (
        SELECT AVG(maintenance_cost)
        FROM station_maintenance
    )
);

external_knowledge:
- 'bustling' refers to charging stations with high energy usage;
- 'actively running' stations are those with a 'status' of 'operational';
- 'high energy demand' implies stations with energy consumption exceeding the average energy consumption of all operational stations.

sql:
SELECT session_id, station_id, vehicle_id, user_id, start_date_time, total_duration, energy_kWh, session_cost, session_status
FROM charging_sessions
WHERE session_status = 'in progress';

SELECT SUM(energy_kWh) AS total_energy_used
FROM charging_sessions
WHERE station_id = 0;

SELECT COUNT(DISTINCT station_id) 
FROM station_maintenance 
WHERE status = 'completed';

SELECT cs.station_name, cs.operational_hours, f.feedback_text
FROM charging_stations cs
JOIN feedback f ON cs.station_id = f.station_id;
